/**
 * A level of logging output, debug/info/warn/error, or none
 * @typedef Level
 */
enum Level {
    none = 'none',
    debug = 'debug',
    info = 'info',
    warn = 'warn',
    error = 'error',
}

export default Level;

export const levelOrder: Level[] = [
    Level.debug,
    Level.info,
    Level.warn,
    Level.error,
    Level.none,
];
