import Log from './Log';
import {Level, Output} from './types';

/**
 * LogOutputs class - logging level for each output channel
 * @class LogOutputs
 * @param {Log} [_log] The log on which this is the outputs property
 * @param {string} [_namespace?] Defaults to the log's namespace, but overridable
 */
class LogOutputs {

    constructor(private _log: Log) {
        if(!this._log) {
            throw new Error('log is a required parameter');
        }
    }

    /**
     * Set the logging level for all output channels at once
     * @name LogOutputs#all
     * @type {Level}
     */
    set all(level: Level|keyof typeof Level) {
        this.console = level;
        this.file = level;
        this.pegasus = level;
        this.syslog = level;
    }

    /**
     * The logging level for the console output channel
     * @name LogOutputs#console
     * @type {Level}
     */
    set console(level: Level|keyof typeof Level) {
        this._log.setLevelForOutput(Output.console, <Level>level);
    }
    get console(): Level|keyof typeof Level {
        return this._log.getLevelForOutput(Output.console);
    }

    /**
     * The logging level for the file output channel
     * @name LogOutputs#file
     * @type {Level}
     */
    set file(level: Level|keyof typeof Level) {
        this._log.setLevelForOutput(Output.file, <Level>level);
    }
    get file(): Level|keyof typeof Level {
        return this._log.getLevelForOutput(Output.file);
    }

    /**
     * The logging level for the Pegasus output channel
     * @name LogOutputs#pegasus
     * @type {Level}
     */
    set pegasus(level: Level|keyof typeof Level) {
        this._log.setLevelForOutput(Output.pegasus, <Level>level);
    }
    get pegasus(): Level|keyof typeof Level {
        return this._log.getLevelForOutput(Output.pegasus);
    }

    /**
     * The logging level for the syslog output channel
     * @name LogOutputs#syslog
     * @type {Level}
     */
    set syslog(level: Level|keyof typeof Level) {
        this._log.setLevelForOutput(Output.syslog, <Level>level);
    }
    get syslog(): Level|keyof typeof Level {
        return this._log.getLevelForOutput(Output.syslog);
    }

}

export default LogOutputs;
