global.Singletons = global.Singletons || {};

declare var global:any;

class Singletons {
    // check an instantiated class and return it or it's previously instantiated singleton
    static enforce<T>(candidate: {new(): T}):Function;
    static enforce(candidate:Function):Function;
    static enforce(candidate:any|Function):any|Function {
        let singleton:any = candidate;
        let singletonName:string = candidate.name;
        if(!global.Singletons[singletonName]) {
            global.Singletons[singletonName] = singleton;
        }
        else {
            singleton = global.Singletons[singletonName];
            // let's only warn if the versions don't match
            // console.warn(
                // 'Singletons: using existing singleton',
                // singletonName
            // );
            // optionally check if versions match (and warn if not)
            if(candidate.version) {
                let candidateVersion:string|Function = candidate.version;
                let singletonVersion = singleton.version;
                if(typeof candidate.version === 'function') {
                    candidateVersion = candidate.version();
                }
                if(typeof singleton.version === 'function') {
                    singletonVersion = singleton.version();
                }
                if(candidateVersion !== singletonVersion) {
                    console.log(
                        singletonName,
                        'singleton: existing version',
                        singletonVersion,
                        'does not equal candidate version',
                        candidateVersion
                    );
                }
            }
        }
        return singleton;
    }
}

export default Singletons;
