import {formatItem} from '../utils';
import {Level} from '../types';
import osHomedir = require('os-homedir');
import OutputHandler from './OutputHandler';
import path = require('path');
import RFS = require('rotating-file-stream');
import stream = require('stream');

const DEFAULT_CONFIG: FileConfig = Object.freeze({
    filename: null,
    size: '10M',
    compress: true,
    outputFileAndLine: false,
});

/**
 * Filesystem output configuration
 * @interface FileConfig
 */
export interface FileConfig {

    /**
     * The filename to write to write
     * @name FileConfig#filename
     * @type {string}
     */
    filename: string;

    /**
     * The file size at which to rotate the log
     * Accepts a positive integer followed by one of these possible letters:
     * B: Bytes
     * K: KiloBytes
     * M: MegaBytes
     * G: GigaBytes
     * @name FileConfig#size
     * @type {string}
     */
    size?: string;

    /**
     * The time interval at which to rotate
     * Accepts a positive integer followed by one of these possible letters:
     * s: seconds. Accepts integer divider of 60.
     * m: minutes. Accepts integer divider of 60.
     * h: hours. Accepts integer divider of 24.
     * d: days
     * @name FileConfig#interval
     * @type {string}
     */
    interval?: string;

    /**
     * Whether or not to gzip compress logs after they are rotated
     * @name FileConfig#compress
     * @type {boolean}
     */
    compress?: boolean;

    /**
     * Whether or not to add the filename and line number to each line logged
     * @name FileConfig#outputFileAndLine
     * @type {boolean}
     */
    outputFileAndLine?: boolean;
}

/**
 * Output channel that logs to the filesystem
 * @class FileHandler
 */
export default class FileHandler extends OutputHandler<FileConfig> {

    // The rotating writable file stream
    private _stream: stream.Writable;

    constructor() {
        super();
        // If FileConfig ever goes below depth one, this will need to be
        // changed to a deep copy (lodash.assign)
        this._config = Object.freeze(Object.assign({}, DEFAULT_CONFIG));
    }

    write(
        time: Date,
        robotID: string,
        transID: string,
        processName: string,
        release: string,
        namespace: string,
        level: Level,
        ...args: any[],
    ): void {
        // only write to file if the writable stream is initialized
        if(this._stream) {
            const timestamp = time.toISOString();
            const items = [
                ...args.map(item => formatItem(item)),
                ...(this._config.outputFileAndLine
                    ? [new Error().stack.split('\n')[4]]
                    : []),
            ];
            const message = `${namespace}: ${items.join(' ')}`;
            const versions = `[versions@1 release="${release}"]`;
            const transaction = transID ? `[messageContext@1 transID="${transID}"]` : '';
            const structuredData = `${versions}${transaction}`;
            const fullText = `${timestamp} ${robotID || '-'} ${processName}[${process.pid},${level}]: ${structuredData || '-'} ${message}\n`;
            this._stream._write(fullText, 'utf-8', console.error);
        }
    }

    /**
     * The filesystem output configuration for this handler
     * @name FileHandler#config
     * @type {FileConfig}
     */
    set config(config: FileConfig) {
        const oldConfig = this._config;
        this._config = Object.freeze(Object.assign({}, this._config, config));
        if(this._stream) {
            this._stream.end();
        }
        if(config.filename && oldConfig.filename !== config.filename) {
            if(config.filename.length > 0) {
                try {
                    this._createStream();
                }
                catch(err) {
                    console.warn('Error opening log file for output,', err);
                }
            }
            else {
                // rotating-file-stream doesn't provide a way to close the file
                // lame.
                this._stream = null;
            }
        }
    }
    get config(): FileConfig {
        return this._config;
    }

    private _createStream() {
        const filePath = path.resolve(this._config.filename.startsWith('~/')
            ? path.join(osHomedir(), this._config.filename.slice(2))
            : this._config.filename);
        const options: any = {};
        if(this._config.size) {
            options.size = this._config.size;
        }
        if(this._config.interval) {
            options.interval = this._config.interval;
        }
        if(this._config.compress) {
            options.compress = 'gzip';
        }
        this._stream = new RFS(filePath, options);
    }
}
