import ConsoleHandler, {ConsoleConfig} from './ConsoleHandler';
import FileHandler, {FileConfig} from './FileHandler';
import OutputHandler from './OutputHandler';
import SyslogHandler, {SyslogConfig} from './SyslogHandler';
import {Output} from '../types';

export interface OutputHandlers {
    [key: string]: OutputHandler<Object>;
}

const consoleHandler = new ConsoleHandler();
const fileHandler = new FileHandler();
const syslogHandler = new SyslogHandler();

export const outputHandlers: OutputHandlers = {
    [Output.console]: consoleHandler,
    [Output.file]: fileHandler,
    [Output.syslog]: syslogHandler,
};

export {
    ConsoleConfig,
    ConsoleHandler,
    FileConfig,
    FileHandler,
    OutputHandler,
    SyslogConfig,
    SyslogHandler,
};
