export type PlatformVersion = {version: string};

export default function getPlatformVersion(): PlatformVersion {
    // Get the platform build version
    let tbd: PlatformVersion;
    try {
        tbd = require('/opt/jibo/Jibo/Skills/jibo-tbd/package.json');
    }
    catch (err) {
        tbd = {version: '8.67.5309'};
    }
    return tbd;
}
