import {formatItem} from '../utils';
import {Level} from '../types';
import OutputHandler from './OutputHandler';
import Syslog = require('syslog2-pure-js');

// Default configuration
const DEFAULT_CONFIG: SyslogConfig = Object.freeze({
    port: 514,
    target: '127.0.0.1',
    outputFileAndLine: false,
});

const FACILITY = 'local0';

interface BunyanMessage {
    message?: string;
    frames?: StackFrame[];
}

interface StackFrame {
    column: number;
    filename: string;
    line: number;
    method: string;
}

/**
 * Syslog output configuration
 * @interface SyslogConfig
 */
export interface SyslogConfig {

    /**
     * The port number on which to talk to syslog
     * @name SyslogConfig#port
     * @type {number}
     */
    port?: number;

    /**
     * The target hostname or IP address on which to log
     * @name SyslogConfig#target
     * @type {string}
     */
    target?: string;

    /**
     * Whether or not to add the filename and line number to each line logged
     * @name SyslogConfig#outputFileAndLine
     * @type {boolean}
     */
    outputFileAndLine?: boolean;
}

/**
 * Output channel that logs to syslog (/var/log/messages)
 * Only enabled on linux/arm (e.g. Jibo robot)
 * @class SyslogHandler
 */
export default class SyslogHandler extends OutputHandler<SyslogConfig> {

    // Only enabled on linux/arm (e.g. Jibo robot)
    private _enabled: boolean;

    // The syslog client used for logging
    private _client: Syslog;

    private static _toStructuredData(err: Error): BunyanMessage {
        return Object.getOwnPropertyNames(err).reduce((obj, key) =>
            Object.assign({}, obj, {
                [key === 'stack' ? 'frames' : key]:
                    (key === 'stack'
                        ? JSON.stringify(SyslogHandler._getStackFrames(err))
                        : err[key])
            }),
            {});
    }

    private static _getStackFrames(err: Error): StackFrame[] {
        return err.stack
            // Split on newlines and ignore the first line
            .split('\n').slice(1)
            // Remove spaces from the front and parens from
            // the end, and split on the open paren
            .map(str => str
                .replace(/^    at /, '')
                .replace(/\)$/, '')
                .split(' ('))
            // If there's no name in front, add empty str
            .map(frame => frame.length > 1 ? frame : ['', ...frame])
            // Split the source:line:column
            .map(frame => [frame[0], ...frame[1].split(':')])
            // Return a stack-mapper stack frame
            .map(frame => {
                return {
                    method: frame[0],
                    filename: frame[1],
                    line: parseInt(frame[2]),
                    column: parseInt(frame[3]),
                };
            });
    }

    constructor() {
        super();
        // don't bother on anything other than our linux/arm environment
        this._enabled = process.platform === 'linux' && process.arch === 'arm';
        // If SyslogConfig ever goes below depth one, this will need to be
        // changed to a deep copy (lodash.assign)
        this._config = Object.freeze(Object.assign({}, DEFAULT_CONFIG));
    }

    async write(
        date: Date,
        robotID: string,
        transID: string,
        processName: string,
        release: string,
        namespace: string,
        level: Level,
        ...args: any[],
    ): Promise<void> {
        // only write to syslog if it's enabled
        if (this._enabled) {
            // Create a client if there isn't one already
            if (!this._client) {
                try {
                    await this._createClient();
                } catch (err) {
                    return console.warn('Error connecting to syslog', err);
                }
            }
            const appName = processName;
            const errors = {};
            // Pull errors out of message and into structured data with
            // structured stack traces
            const unformattedItems = args.reduce((items, item, index) => {
                if (item instanceof Error) {
                    errors[index] =
                        SyslogHandler._toStructuredData(item);
                    // Add the error message to the log-message body
                    return [...items, item.message];
                } else {
                    // Add the entire non-Error item to the log-message body
                    return [...items, item];
                }
            }, []);
            // Format items and add file and line, if required
            const logArgs = unformattedItems.map(item => formatItem(item));
            if (this._config && this._config.outputFileAndLine) {
                // The first four items on the stack are from jibo-log:
                // 1. Log#debug/info/warn/error
                // 2. Log#_log
                // 3. forEach(output: OutputHandler)
                // 4. OutputHandler#write
                logArgs.push(new Error().stack.split('\n')[4]);
            }
            const message = `${namespace}: ${logArgs.join(' ')}`;
            const severity =
                level === Level.error
                    ? 'ERR'
                    : level.toString().toUpperCase();
            // Build up the structured data object
            const structuredData = {
                ...(Object.keys(errors).length ? errors : {}),
                versions: {release},
                ...(transID ? {messageContext: {transID}} : {})
            };
            // Create a Glossy record for output
            const record = {appName, date, message, severity, structuredData};
            // Write it out to the syslog daemon
            this._client.write(record);
        }
    }

    /**
     * The syslog output configuration for this handler
     * @name SyslogHandler#config
     * @type {SyslogConfig}
     */
    set config(config: SyslogConfig) {
        this._config = Object.freeze(Object.assign({}, this._config, config));
    }
    get config(): SyslogConfig {
        return this._config;
    }

    // Create a syslog client on the configured port and IP/hostname
    private _createClient(): Promise<void> {
        return new Promise((resolve, reject) => {
            this._client = Syslog.create({
                connection: {
                    host: this._config.target,
                    port: this._config.port,
                },
                facility: FACILITY,
                PEN: 1,
                useStructuredData: true,
            }, err => {
                if (err) {
                    this._client = undefined;
                    reject(err);
                } else {
                    resolve();
                }
            });
        });
    }
}
