import util = require('util');
import {format} from 'format-error';

// Format the passed object for string output
const FORMAT_ERROR_OPTIONS: any = {
    noColor: true
};
const INSPECT_OPTIONS: util.InspectOptions = {
    depth: 3,
    maxArrayLength: 10,
};

function _formatError(error: string | Error): string {
    return _formatObject(format(error, FORMAT_ERROR_OPTIONS));
}

function _formatObject(obj: any): string {
    return util.inspect(obj, INSPECT_OPTIONS);
}

/**
 * Format the passed item as a single-line string for logging (i.e. syslog)
 * @function formatItem
 * @param args {any[]} Item to format
 * @return {string} Formatted line, ready for logging
 */
export function formatItem(item: any): string {
    // If the object has a method specifically for logging usage, then use that
    // instead of the original
    const preformatted =
        item && typeof item.toLog === 'function' ? item.toLog() : item;
    const message =
        typeof preformatted === 'string' ? preformatted.trim() :
        preformatted instanceof Error ? _formatError(preformatted) :
        _formatObject(preformatted);
    return message
        // Replace '\n' strings with '\\n'
        .replace(/\\n/g, '\\\\n')
        // Replace newlines with '\n'
        .replace(/\r?\n/g, '\\n');
}
